What is printed by the following ANSI C program?

#include<stdio.h>
int main(int argc, char *argv[]) {
    char a = 'P';
    char b = 'x';
    char c = (a&b) + '*';
    char d = (a|b) - '-';
    char e = (a^b) + '+';
    printf("%c %c %c\n", c, d, e);
    return 0;
}

ASCII encoding for relevant characters:
A=65, B=66, ..., Z=90, a=97, b=98, c=99, ..., z=122
*=42, +=43, -=45

A. z K S
B. 122 75 83
C. * - +
D. P x +

The integer value printed by the ANSI-C program given below is _______________

#include<stdio.h>
int funcp(){
    static int x = 1;
    x++;
    return x;
}
int main(){
    int x;
    int y;
    x = funcp();
    y = funcp();
    printf("%d\n", x+y);
    return 0;
}
